import "./AddRecipe.css"; // ✅ uses your existing CSS
import { useEffect, useState } from "react";
import axios from "axios";
import { useNavigate, useParams } from "react-router-dom";
import UserNavbar from "./UserNavbar";

export default function EditRecipe() {
  const { id } = useParams();
  const navigate = useNavigate();

  const [formData, setFormData] = useState({
    title: "",
    ingredients: "",
    steps: "",
    cooking_time: "",
    difficulty: "",
    image: null,
  });

  // ================= FETCH EXISTING RECIPE =================
  useEffect(() => {
    const token = localStorage.getItem("token");

    if (!token) {
      alert("Please login first ❌");
      navigate("/login");
      return;
    }

    axios
      .get(`http://127.0.0.1:8000/api/recipes/${id}/`, {
        headers: {
          Authorization: `Token ${token}`,
        },
      })
      .then((res) => {
        setFormData({
          title: res.data.title,
          ingredients: res.data.ingredients,
          steps: res.data.steps,
          cooking_time: res.data.cooking_time,
          difficulty: res.data.difficulty,
          image: null, // don't auto-set old image
        });
      })
      .catch(() => {
        alert("Failed to load recipe ❌");
        navigate("/myrecipe");
      });
  }, [id, navigate]);

  // ================= HANDLE INPUT =================
  const handleChange = (e) => {
    const { name, value, files } = e.target;
    setFormData({
      ...formData,
      [name]: files ? files[0] : value,
    });
  };

  // ================= UPDATE RECIPE =================
  const handleSubmit = async (e) => {
    e.preventDefault();
    const token = localStorage.getItem("token");

    const data = new FormData();
    data.append("title", formData.title);
    data.append("ingredients", formData.ingredients);
    data.append("steps", formData.steps);
    data.append("cooking_time", formData.cooking_time);
    data.append("difficulty", formData.difficulty);
    if (formData.image) data.append("image", formData.image);

    try {
      await axios.put(
        `http://127.0.0.1:8000/api/recipes/edit/${id}/`,
        data,
        {
          headers: {
            Authorization: `Token ${token}`,
            "Content-Type": "multipart/form-data",
          },
        }
      );

      alert("Recipe updated successfully ✅");
      navigate("/myrecipe");
    } catch (error) {
      console.error(error);
      alert("Failed to update recipe ❌");
    }
  };

  // ================= UI =================
  return (
    <>
      <UserNavbar />

      <div className="add-container">
        <div className="add-card">
          <h2>Edit Recipe</h2>

          <form onSubmit={handleSubmit}>
            <input
              type="text"
              name="title"
              placeholder="Title"
              value={formData.title}
              onChange={handleChange}
              required
            />

            <textarea
              name="ingredients"
              placeholder="Ingredients"
              value={formData.ingredients}
              onChange={handleChange}
              required
            />

            <textarea
              name="steps"
              placeholder="Steps"
              value={formData.steps}
              onChange={handleChange}
              required
            />

            <input
              type="number"
              name="cooking_time"
              placeholder="Cooking Time"
              value={formData.cooking_time}
              onChange={handleChange}
              required
            />

            <select
              name="difficulty"
              value={formData.difficulty}
              onChange={handleChange}
              required
            >
              <option value="">Select Difficulty</option>
              <option value="easy">Easy</option>
              <option value="medium">Medium</option>
              <option value="hard">Hard</option>
            </select>

            <input type="file" name="image" onChange={handleChange} />

            <button type="submit">Update Recipe</button>
          </form>
        </div>
      </div>
    </>
  );
}
